  void sse_encode_rdp_config(RdpConfig self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_String(self.targetHost, serializer);
    sse_encode_u_16(self.targetPort, serializer);
    sse_encode_String(self.username, serializer);
    sse_encode_String(self.password, serializer);
    sse_encode_opt_String(self.domain, serializer);
    sse_encode_u_16(self.width, serializer);
    sse_encode_u_16(self.height, serializer);
    sse_encode_String(self.security, serializer);
    sse_encode_opt_String(self.expectedFingerprint, serializer);
  }

  @protected
  void sse_encode_rdp_event(RdpEvent self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case RdpEvent_Started(sessionId: final sessionId):
        sse_encode_i_32(0, serializer);
        sse_encode_u_32(sessionId, serializer);
      case RdpEvent_Connected(
        cert: final cert,
        desktopWidth: final desktopWidth,
        desktopHeight: final desktopHeight,
      ):
        sse_encode_i_32(1, serializer);
        sse_encode_box_autoadd_rdp_cert_info(cert, serializer);
        sse_encode_u_16(desktopWidth, serializer);
        sse_encode_u_16(desktopHeight, serializer);
      case RdpEvent_CertMismatch(fingerprint: final fingerprint):
        sse_encode_i_32(2, serializer);
        sse_encode_String(fingerprint, serializer);
      case RdpEvent_FrameUpdate(
        x: final x,
        y: final y,
        width: final width,
        height: final height,
        rgba: final rgba,
      ):
        sse_encode_i_32(3, serializer);
        sse_encode_u_16(x, serializer);
        sse_encode_u_16(y, serializer);
        sse_encode_u_16(width, serializer);
        sse_encode_u_16(height, serializer);
        sse_encode_list_prim_u_8_strict(rgba, serializer);
      case RdpEvent_ClipboardText(text: final text):
        sse_encode_i_32(4, serializer);
        sse_encode_String(text, serializer);
      case RdpEvent_Disconnected(reason: final reason):
        sse_encode_i_32(5, serializer);
        sse_encode_String(reason, serializer);
      case RdpEvent_Error(message: final message):
        sse_encode_i_32(6, serializer);
        sse_encode_String(message, serializer);
    }
  }

  @protected
  void sse_encode_u_16(int self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    serializer.buffer.putUint16(self);
  }

  @protected
  void sse_encode_u_32(int self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    serializer.buffer.putUint32(self);
  }

  @protected
  void sse_encode_u_8(int self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    serializer.buffer.putUint8(self);
  }

  @protected
  void sse_encode_unit(void self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
  }

  @protected
  void sse_encode_i_32(int self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    serializer.buffer.putInt32(self);
  }
}
